class DatabaseLogger {
  static final DatabaseLogger _instance = DatabaseLogger._internal();
  factory DatabaseLogger() => _instance;
  DatabaseLogger._internal();

  void logQuery(String operation, String table, String query, [Map<String, dynamic>? params]) {
    ProductionLogger().logDatabaseOperation(operation, table, query);
    if (params != null) {
      debugPrint('QUERY PARAMETERS: $params');
    }
  }

  void logTransaction(String operation, List<String> queries) {
    ProductionLogger().logDatabaseOperation('TRANSACTION', 'multiple', 'BEGIN');
    for (var query in queries) {
      debugPrint('TRANSACTION QUERY: $query');
    }
    ProductionLogger().logDatabaseOperation('TRANSACTION', 'multiple', 'END');
  }
}

